/**
 * element-tracker.ts
 *
 * Singleton global tracker để theo dõi vị trí và kích thước của một element.
 * Dùng chung cho các component như NewDropdown (blockScroll=false), Tooltip, Popover...
 *
 * Cơ chế:
 * - ResizeObserver: phát hiện element thay đổi kích thước.
 * - scroll event (capture, passive): phát hiện scroll ở bất kỳ container nào.
 *   Chỉ đăng ký 1 listener duy nhất trên window; tự tháo khi không còn element nào.
 * - IntersectionObserver: phát hiện trigger đi vào/ra viewport để cập nhật rect.
 *
 * Mỗi element chỉ được track bởi 1 callback tại một thời điểm.
 * Gọi `untrackElement(el)` để dừng theo dõi và giải phóng bộ nhớ.
 */

export type TrackedRect = {
  top: number;
  left: number;
  width: number;
  height: number;
};

type TrackCallback = (rect: TrackedRect) => void;

// ── Singleton state ──────────────────────────────────────────────────────────

const callbacks = new Map<Element, TrackCallback>();

// ResizeObserver: fires khi target thay đổi kích thước
const resizeObserver = new ResizeObserver(entries => {
  for (const entry of entries) {
    const cb = callbacks.get(entry.target);
    if (cb) cb(getRect(entry.target));
  }
});

// IntersectionObserver: bắt khi trigger đi vào/ra viewport (bị scroll ra khỏi tầm nhìn)
const intersectionObserver = new IntersectionObserver(
  entries => {
    for (const entry of entries) {
      const cb = callbacks.get(entry.target);
      if (cb) cb(getRect(entry.target));
    }
  },
  { threshold: [0, 1] },
);

// scroll listener dùng chung — capture phase để bắt scroll ở mọi container
// rAF dedup: gộp tất cả scroll events trong cùng 1 frame thành 1 lần getBoundingClientRect
let rafId = 0;

const onScroll = () => {
  if (rafId) return; // frame đã pending → bỏ qua, tránh gọi getBoundingClientRect nhiều lần/frame
  rafId = requestAnimationFrame(() => {
    rafId = 0;
    callbacks.forEach((cb, el) => cb(getRect(el)));
  });
};
let scrollListenerAttached = false;

function attachScrollListener() {
  if (!scrollListenerAttached) {
    window.addEventListener('scroll', onScroll, { passive: true, capture: true });
    scrollListenerAttached = true;
  }
}

function detachScrollListener() {
  if (scrollListenerAttached && callbacks.size === 0) {
    window.removeEventListener('scroll', onScroll, { capture: true });
    scrollListenerAttached = false;
    if (rafId) {
      cancelAnimationFrame(rafId);
      rafId = 0;
    }
  }
}

function getRect(el: Element): TrackedRect {
  const r = el.getBoundingClientRect();
  return { top: r.top, left: r.left, width: r.width, height: r.height };
}

// ── Public API ───────────────────────────────────────────────────────────────

/**
 * Bắt đầu theo dõi vị trí của `el`.
 * `callback` sẽ được gọi ngay lập tức với rect hiện tại,
 * và mỗi khi el thay đổi kích thước hoặc scroll.
 */
export function trackElement(el: Element, callback: TrackCallback): void {
  callbacks.set(el, callback);
  resizeObserver.observe(el);
  intersectionObserver.observe(el);
  attachScrollListener();
  // Gọi ngay để caller có rect ban đầu
  callback(getRect(el));
}

/**
 * Dừng theo dõi `el` và giải phóng bộ nhớ.
 */
export function untrackElement(el: Element): void {
  callbacks.delete(el);
  resizeObserver.unobserve(el);
  intersectionObserver.unobserve(el);
  detachScrollListener();
}
